import React, { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import { API_MOVIE, API_TV, API_KEY } from '../constant';
import { FiChevronLeft, FiChevronRight } from 'react-icons/fi';
import axios from 'axios';

const Video = (props) => {

  const { id, name } = props;
  const [data, setData] = useState([]);

  let api;
  switch (name) {
    case 'movie':
      api = API_MOVIE;
      break;

    case 'tv':
      api = API_TV;
      break;

    default:
      break;
  }

  useEffect(() => {
    const getData = async () => {
      axios.get(api + id + '/videos?api_key=' + API_KEY)
        .then((data) => {
          setData(data.data.results);
        })
        .catch((error) => {
          console.error(error);
        })
    }

    getData();
  }, [api, id]);

  const ref = useRef(null);

  const scrollRight = (scrollOffset) => {
    ref.current.scrollLeft -= scrollOffset;
    if(!(ref.current.scrollLeft < (ref.current.scrollWidth-(ref.current.clientWidth*1.25)))) {
      ref.current.children[1].classList.remove('hide');
    }
    if(ref.current.scrollLeft <= 500) {
      ref.current.children[0].classList.add('hide');
    }
  };

  const scrollLeft = (scrollOffset) => {
    ref.current.scrollLeft += scrollOffset;
    if(!(ref.current.scrollLeft < (ref.current.scrollWidth-(ref.current.clientWidth*1.25)))) {
      ref.current.children[1].classList.add('hide');
    }
    if(ref.current.scrollLeft >= 0) {
      ref.current.children[0].classList.remove('hide');
    }
  };

  return (
      data.length > 0 ?
        <div className="mt-4">
        <div>{data.filter((item) => item.type === "Trailer").map((dataTrailer, index) => (index < 1 && dataTrailer ? <a key={index} href={"https://www.youtube.com/watch?v=" + dataTrailer.key} target="_blank" rel="noreferrer">{console.log(index)}<button className="btn btn-primary">Watch Trailer</button></a> : null))}</div>
        <div className="mt-5 position-relative">
          <h2>VIDEOS</h2>
          <div className="d-flex flex-row" ref={ref}>
          <button className="btn btn-primary position-absolute scroll-button1 hide" onClick={() => scrollRight(500)}><FiChevronLeft /></button>
          <button className="btn btn-primary position-absolute scroll-button2" onClick={() => scrollLeft(500)}><FiChevronRight /></button>
            {data.map((dataRow, index) => (
              <Link key={index} className="card-link" to='/movieshub/'>
                <div className="card" key={index}>
                  <div className="card-body">
                    <div className="card-text">
                      <iframe src={"https://www.youtube.com/embed/" + dataRow.key} title={dataRow.name} frameBorder="0" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" allowFullScreen></iframe>
                      <div>{dataRow.name ? dataRow.name : dataRow.title}</div>
                    </div>
                  </div>
                </div>
              </Link>
            ))}
          </div>
        </div>
        </div>
         : null
  )
}

export default Video
